import React from "react";

const Navbar = () => {
    return (
        <nav>
            <figure className="logo">
                <a href="index.html">
                    <img src="images/logo.png" alt="Movie Finder" />
                </a>
            </figure>
            <button id="showBookmarksButton">
                <i className="fas fa-bookmark fa-2x"></i>
            </button>
        </nav>
    );
};

export default Navbar;
